        imageViewSharedContent = findViewById(R.id.imageViewSharedContent)

        handleIncomingIntent(intent)
    }

    override fun onNewIntent(intent: Intent?) {
        super.onNewIntent(intent)
        intent?.let { handleIncomingIntent(it) }
    }

    private fun handleIncomingIntent(intent: Intent) {
        // Validate the intent action strictly
        if (intent.action != Intent.ACTION_SEND) {
            Log.w(TAG, "Received unexpected action: ${intent.action}")
            showErrorAndFinish("Unsupported action.")
            return
        }

        // Validate that the intent has a proper category or came from the share sheet
        val type = intent.type
        if (type.isNullOrBlank()) {
            Log.w(TAG, "Received intent with null or blank MIME type.")
            showErrorAndFinish("No content type specified.")
            return
        }

        when {
            type == "text/plain" -> handleSharedText(intent)
            type.startsWith("image/") -> handleSharedImage(intent, type)
            else -> {
                Log.w(TAG, "Unsupported MIME type: $type")
                showErrorAndFinish("Unsupported content type: $type")
            }
        }
    }

    private fun handleSharedText(intent: Intent) {
        val sharedText = intent.getStringExtra(Intent.EXTRA_TEXT)

        if (sharedText.isNullOrBlank()) {
            Log.w(TAG, "Shared text is null or blank.")
            showErrorAndFinish("No text content received.")
            return
        }

        // Enforce maximum length to prevent DoS via extremely large strings
        if (sharedText.length > MAX_TEXT_LENGTH) {
            Log.w(TAG, "Shared text exceeds maximum allowed length.")
            showErrorAndFinish("Shared text is too long.")
            return
        }

        // Sanitize the text: strip control characters except newlines and tabs
        val sanitizedText = sanitizeText(sharedText)

        // Check if it looks like a URL
        val extractedUrl = extractAndValidateUrl(sanitizedText)

        if (extractedUrl != null) {
            processSharedUrl(extractedUrl)
        } else {
            processSharedPlainText(sanitizedText)
