    }

    private fun sanitizeText(input: String): String {
        // Remove control characters except \n, \r, \t
        return input.replace(Regex("[\\p{Cc}&&[^\n\r\t]]"), "").trim()
    }

    private fun extractAndValidateUrl(text: String): String? {
        val trimmed = text.trim()

        // Check if the entire text is a URL using Android's Patterns
        if (!Patterns.WEB_URL.matcher(trimmed).matches()) {
            return null
        }

        // Parse and validate the URL more strictly
        return try {
            val uri = URI(trimmed)
            val scheme = uri.scheme?.lowercase()

            // Only allow http and https schemes for URLs
            if (scheme != "http" && scheme != "https") {
                Log.w(TAG, "Rejected URL with disallowed scheme: $scheme")
                return null
            }

            val host = uri.host
            if (host.isNullOrBlank()) {
