            Log.w(TAG, "Failed to parse URL: ${e.message}")
            null
        }
    }

    private fun isPrivateOrLoopbackHost(host: String): Boolean {
        val lower = host.lowercase()
        if (lower == "localhost" || lower == "127.0.0.1" || lower == "::1" || lower == "[::1]") {
            return true
        }
        // Check common private IP ranges
        if (lower.startsWith("10.") || lower.startsWith("192.168.")) {
