    private fun copyImageToPrivateStorage(sourceUri: Uri) {
        try {
            val inputStream = contentResolver.openInputStream(sourceUri) ?: return
            val fileName = "shared_image_${System.currentTimeMillis()}"
            val outputStream = openFileOutput(fileName, MODE_PRIVATE)

            inputStream.use { input ->
                outputStream.use { output ->
